This is a missed-optimization in InstCombine.

The following program reveals the missed optimization.
The source program is
```llvm
define i1 @test_icmp_sgt_and_negpow2_c(i32 %add) {
  %and = and i32 %add, -32
  %cmp = icmp sgt i32 %and, 16
  ret i1 %cmp
}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define i1 @test_icmp_sgt_and_negpow2_c(i32 %add) {
  %cmp = icmp sgt i32 %add, 31
  ret i1 %cmp
}

```
Please modify the following code in llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp:InstCombinerImpl::foldICmpAndConstConst to implement the missed optimization:
```cpp

  // For vectors: icmp ne (and X, 1), 0 --> trunc X to N x i1
  // TODO: We canonicalize to the longer form for scalars because we have
  // better analysis/folds for icmp, and codegen may be better with icmp.
  if (isICMP_NE && Cmp.getType()->isVectorTy() && C1.isZero() &&
      match(And->getOperand(1), m_One()))
    return new TruncInst(And->getOperand(0), Cmp.getType());

  const APInt *C2;
  Value *X;
  if (!match(And, m_And(m_Value(X), m_APInt(C2))))
    return nullptr;

  // Don't perform the following transforms if the AND has multiple uses
  if (!And->hasOneUse())
    return nullptr;

  if (Cmp.isEquality() && C1.isZero()) {
    // Restrict this fold to single-use 'and' (PR10267).
    // Replace (and X, (1 << size(X)-1) != 0) with X s< 0
    if (C2->isSignMask()) {
      Constant *Zero = Constant::getNullValue(X->getType());
      auto NewPred = isICMP_NE ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_SGE;
      return new ICmpInst(NewPred, X, Zero);
    }

